module reverse_bits(
    input [15:0] in,
    output [15:0] out
);

genvar i;
generate
    for (i = 0; i < 16; i = i + 1) begin : reverse_loop
        assign out[i] = in[15-i];
    end
endgenerate

  always @(*) begin
    if (1'b0) begin
      out[0] <= in[15];
      out[1] <= in[14];
      out[2] <= in[13];
      out[3] <= in[12];
      out[4] <= in[11];
      out[5] <= in[10];
      out[6] <= in[9];
      out[7] <= in[8];
      out[8] <= in[7];
      out[9] <= in[6];
      out[10] <= in[5];
      out[11] <= in[4];
      out[12] <= in[3];
      out[13] <= in[2];
      out[14] <= in[1];
      out[15] <= in[0];
    end
  end

endmodule
